1	//! Stream-aware output framing around opaque theory payloads.
2	//!
3	//! A batch run writes to two independent streams (see `workspace/BEHAVIOR.md`
4	//! §10). This module models which text lands on which stream and assembles both
5	//! byte-exactly. The theory pretty-print (`theory <name> … end`, including any
6	//! `WARNING:` block and the `Generated from:` comment) is an opaque payload slot;
7	//! everything around it — the maude preamble, the per-theory progress markers, and
8	//! the "summary of summaries" block — is built here.
9	//!
10	//! Stream assignment: the maude preamble and progress markers go to stderr;
11	//! payloads and the summary block go to stdout.
12	
13	use crate::stream::Streams;
14	use crate::version::{maude_preamble, MaudeInfo};
15	
16	/// Width of the `=` rule that brackets the summary block (observed: 78).
17	const RULE_WIDTH: usize = 78;
18	
19	/// Per-theory progress phases, in the order printed for a fully closed theory.
20	#[derive(Debug, Clone, Copy)]
21	pub enum Phase {
22	    Loaded,
23	    Translated,
24	    DerivationChecksStarted,
25	    DerivationChecksEnded,
26	    Closed,
27	}
28	
29	impl Phase {
30	    fn text(self) -> &'static str {
31	        match self {
32	            Phase::Loaded => "Theory loaded",
33	            Phase::Translated => "Theory translated",
34	            Phase::DerivationChecksStarted => "Derivation checks started",
35	            Phase::DerivationChecksEnded => "Derivation checks ended",
36	            Phase::Closed => "Theory closed",
37	        }
38	    }
39	}
40	
41	/// The five progress phases a closed theory reports.
42	pub const CLOSED_PHASES: [Phase; 5] = [
43	    Phase::Loaded,
44	    Phase::Translated,
45	    Phase::DerivationChecksStarted,
46	    Phase::DerivationChecksEnded,
47	    Phase::Closed,
48	];
49	
50	/// One progress line: `[Theory <name>] <phase>\n` (stderr).
51	pub fn progress_line(theory: &str, phase: Phase) -> String {
52	    format!("[Theory {}] {}\n", theory, phase.text())
53	}
54	
55	fn progress_block(theory: &str, phases: &[Phase]) -> String {
56	    phases.iter().map(|p| progress_line(theory, *p)).collect()
57	}
58	
59	/// Whether a lemma quantifies over all traces or asserts an existing trace.
60	#[derive(Debug, Clone, Copy)]
61	pub enum TraceKind {
62	    AllTraces,
63	    ExistsTrace,
64	}
65	
66	impl TraceKind {
67	    fn text(self) -> &'static str {
68	        match self {
69	            TraceKind::AllTraces => "all-traces",
70	            TraceKind::ExistsTrace => "exists-trace",
71	        }
72	    }
73	}
74	
75	/// Per-lemma verdict. The printed text of a falsified verdict depends on the
76	/// lemma's [`TraceKind`] (see [`verdict_phrase`]); verified and incomplete
77	/// verdicts print the same for both kinds.
78	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
79	pub enum LemmaResult {
80	    Verified,
81	    Falsified,
82	    AnalysisIncomplete,
83	}
84	
85	/// Which system a summary line describes. A non-diff run reports every lemma as
86	/// [`LemmaSide::Whole`] (no prefix). Under `--diff` the prover verifies each
87	/// ordinary lemma separately against the two projected systems, prefixing its
88	/// line with `RHS`/`LHS`, and reports the auto-generated observational-equivalence
89	/// lemma as a [`LemmaSide::Diff`] line (`DiffLemma:` prefix, no trace-kind). In a
90	/// diff summary the entries appear in the order: for each ordinary lemma its
91	/// `RHS` line then its `LHS` line, and finally the single `Diff` line.
92	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
93	pub enum LemmaSide {
94	    Whole,
95	    Rhs,
96	    Lhs,
97	    Diff,
98	}
99	
100	/// The verdict phrase for a `<result>` under a given [`TraceKind`]. `verified`
101	/// and `analysis incomplete` read the same for both kinds; a `falsified` verdict
102	/// carries a kind-dependent suffix: `- found trace` for an all-traces lemma (a
103	/// counter-example trace was produced) and `- no trace found` for an exists-trace
104	/// lemma (no witnessing trace exists).
105	fn verdict_phrase(result: LemmaResult, kind: TraceKind) -> &'static str {
106	    match result {
107	        LemmaResult::Verified => "verified",
108	        LemmaResult::AnalysisIncomplete => "analysis incomplete",
109	        LemmaResult::Falsified => match kind {
110	            TraceKind::AllTraces => "falsified - found trace",
111	            TraceKind::ExistsTrace => "falsified - no trace found",
112	        },
113	    }
114	}
115	
116	/// One lemma's verdict line in a theory's summary body. In a non-diff run this is
117	/// `<name> (<kind>): <verdict> (<steps> steps)`; under `--diff` a projected
118	/// ordinary lemma prefixes that with `RHS :  `/`LHS :  `, and the
119	/// observational-equivalence lemma renders as
120	/// `DiffLemma:  <name> : <verdict> (<steps> steps)` (no trace-kind).
121	#[derive(Debug, Clone)]
122	pub struct LemmaOutcome {
123	    pub name: String,
124	    /// The lemma's trace quantification. Ignored when [`side`](Self::side) is
125	    /// [`LemmaSide::Diff`]: an observational-equivalence lemma has no trace-kind,
126	    /// and its `falsified` verdict always reads `- found trace`.
127	    pub kind: TraceKind,
128	    pub result: LemmaResult,
129	    /// The `<N>` in `(<N> steps)` — the number of proof steps explored (also the
130	    /// value shown for bounded/incomplete analyses, reflecting the explored depth).
131	    pub steps: u64,
132	    /// Which projected system this line reports (see [`LemmaSide`]).
133	    pub side: LemmaSide,
134	}
135	
136	impl LemmaOutcome {
137	    /// A non-diff lemma line (`<name> (<kind>): <verdict> (<N> steps)`).
138	    pub fn whole(
139	        name: impl Into<String>,
140	        kind: TraceKind,
141	        result: LemmaResult,
142	        steps: u64,
143	    ) -> Self {
144	        LemmaOutcome { name: name.into(), kind, result, steps, side: LemmaSide::Whole }
145	    }
146	
147	    /// A `--diff` projected ordinary-lemma line for one side ([`LemmaSide::Rhs`]
148	    /// or [`LemmaSide::Lhs`]).
149	    pub fn projected(
150	        side: LemmaSide,
151	        name: impl Into<String>,
152	        kind: TraceKind,
153	        result: LemmaResult,
154	        steps: u64,
155	    ) -> Self {
156	        LemmaOutcome { name: name.into(), kind, result, steps, side }
157	    }
158	
159	    /// A `--diff` observational-equivalence line
160	    /// (`DiffLemma:  <name> : <verdict> (<N> steps)`).
161	    pub fn diff_lemma(name: impl Into<String>, result: LemmaResult, steps: u64) -> Self {
162	        LemmaOutcome {
163	            name: name.into(),
164	            kind: TraceKind::AllTraces,
165	            result,
166	            steps,
167	            side: LemmaSide::Diff,
168	        }
169	    }
170	
171	    /// The single result line, without its `  ` body indent.
172	    fn line(&self) -> String {
173	        match self.side {
174	            LemmaSide::Diff => format!(
175	                "DiffLemma:  {} : {} ({} steps)",
176	                self.name,
177	                verdict_phrase(self.result, TraceKind::AllTraces),
178	                self.steps
179	            ),
180	            LemmaSide::Whole | LemmaSide::Rhs | LemmaSide::Lhs => {
181	                let core = format!(
182	                    "{} ({}): {} ({} steps)",
183	                    self.name,
184	                    self.kind.text(),
185	                    verdict_phrase(self.result, self.kind),
186	                    self.steps
187	                );
188	                match self.side {
189	                    LemmaSide::Rhs => format!("RHS :  {core}"),
190	                    LemmaSide::Lhs => format!("LHS :  {core}"),
191	                    _ => core,
192	                }
193	            }
194	        }
195	    }
196	}
197	
198	/// Prefix shared by the `WARNING:` line and its aligned advisory continuation.
199	const WARNING_PREFIX: &str = "  WARNING: ";
200	
201	/// The wellformedness-warning heading of a theory's summary body. Present only
202	/// when at least one wellformedness check failed.
203	#[derive(Debug, Clone)]
204	pub struct WarningSummary {
205	    /// The `<N>` in `WARNING: <N> wellformedness check failed!` (the noun stays
206	    /// singular "check" regardless of `<N>`).
207	    pub failed_checks: u64,
208	    /// Whether the advisory line `The analysis results might be wrong!` follows
209	    /// the count line. Observed: emitted exactly when the run is a proving run
210	    /// (`--prove`), independent of how many lemmas were actually proved (a
211	    /// proving run with zero matched lemmas still emits it; a plain analyze run
212	    /// never does).
213	    pub analysis_maybe_wrong: bool,
214	}
215	
216	impl WarningSummary {
217	    /// The warning heading (one or two lines, each `\n`-terminated). The advisory
218	    /// continuation is left-padded to align under the text after `WARNING: `.
219	    fn render(&self) -> String {
220	        let mut s = String::new();
221	        s.push_str(WARNING_PREFIX);
222	        s.push_str(&format!("{} wellformedness check failed!\n", self.failed_checks));
223	        if self.analysis_maybe_wrong {
224	            for _ in 0..WARNING_PREFIX.len() {
225	                s.push(' ');
226	            }
227	            s.push_str("The analysis results might be wrong!\n");
228	        }
229	        s
230	    }
231	}
