1	//! Byte-parity tests against captured oracle output.
2	//!
3	//! Fixtures in `tests/fixtures/` are raw captures of the black-box binary. The
4	//! `split_*` fixtures were captured with stdout and stderr redirected separately
5	//! (`1>out 2>err`); the framing tests reassemble BOTH streams and compare them
6	//! byte-for-byte. The `vv_*` fixtures are the value-validation error texts.
7	
8	use cli_clean::args::{parse_args, read_haskell_int, Args, OutputModule, Parsed, PartialEval, StopOnTrace};
9	use cli_clean::emit::{drive_batch, BatchEmitter, StreamCollector};
10	use cli_clean::errors::{app_error, open_file_error, OpenFileError, ParseError};
11	use cli_clean::framing::{
12	    frame_batch, frame_parse_only, frame_variants, render_summary, BatchTheory, LemmaOutcome,
13	    LemmaResult, LemmaSide, LoadedTheory, Summary, TraceKind, WarningSummary,
14	};
15	use cli_clean::stream::{Stream, Streams};
16	use cli_clean::version::{frame_version, MaudeInfo, VersionInfo};
17	use cli_clean::{parse, render_help, render_version, Command, Mode};
