19	fn s(a: &str) -> String {
20	    a.to_string()
21	}
22	fn argv(items: &[&str]) -> Vec<String> {
23	    items.iter().map(|x| x.to_string()).collect()
24	}
25	fn run_err(items: &[&str]) -> ParseError {
26	    parse_args(&argv(items)).unwrap_err()
27	}
28	fn run_ok(items: &[&str]) -> Args {
29	    match parse_args(&argv(items)).unwrap() {
30	        Parsed::Run(a) => a,
31	        other => panic!("expected Run, got {other:?}"),
32	    }
33	}
